const _ = require('lodash');
const problemsData = require('../../data/problems.json');

class ProblemsService {
  /**
   * List problems with optional filters and include component language/status totals.
   * @param {Object} params
   * @param {boolean} params.includeComponents - Whether to include component language/status totals
   * @param {number} params.limit - Maximum number of problems to return
   * @param {string[]} [params.tags] - Tags to filter problems
   * @param {string[]} [params.difficulties] - Difficulties to filter problems
   * @returns {Object} result with problems array and metadata object
   */
  listProblems(params) {
    const { includeComponents, limit, tags, difficulties } = params;

    // Validate limit
    const maxLimit = 1000;
    const safeLimit = Number.isInteger(limit) && limit > 0 ? Math.min(limit, maxLimit) : maxLimit;

    // Filter problems by tags and difficulties
    let filtered = problemsData;
    if (Array.isArray(tags) && tags.length > 0) {
      filtered = filtered.filter(p => p.tags && tags.every(t => p.tags.includes(t)));
    }
    if (Array.isArray(difficulties) && difficulties.length > 0) {
      filtered = filtered.filter(p => p.difficulty && difficulties.includes(p.difficulty));
    }

    // Limit the filtered problems
    const limited = filtered.slice(0, safeLimit);

    // Prepare metadata
    const metadata = {};

    if (includeComponents) {
      // Compute componentLanguageTotals and componentStatusTotals for the limited set
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      limited.forEach(problem => {
        if (problem.components && Array.isArray(problem.components)) {
          problem.components.forEach(component => {
            // Language totals
            if (component.language) {
              componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
            }
            // Status totals
            if (component.status) {
              componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
            }
          });
        }
      });

      metadata.componentLanguageTotals = componentLanguageTotals;
      metadata.componentStatusTotals = componentStatusTotals;
    }

    return {
      problems: limited,
      metadata,
    };
  }
}

module.exports = new ProblemsService
